    <script>
        document.addEventListener('DOMContentLoaded', function() {
            // Use live data source from parent, or a fallback that returns nothing.
            const dataSourceAPI = (typeof parent !== 'undefined' && parent.AutoCardUpdaterAPI) ? parent.AutoCardUpdaterAPI : {
                exportTableAsJson: function() {
                    console.log("No data source found.");
                    return {}; // Return empty object if no source
                },
                registerTableUpdateCallback: function(callback) {
                    console.log("No data source found to register callback.");
                }
            };

            function getTableData() {
                try {
                    return dataSourceAPI.exportTableAsJson();
                } catch (e) {
                    console.error("Error getting table data:", e);
                    return {};
                }
            }

            function processJsonData(json) {
                const tables = {};
                if (!json || typeof json !== 'object') {
                    console.error("Invalid JSON data provided.");
                    return null;
                }
                for (const sheetId in json) {
                    if (Object.prototype.hasOwnProperty.call(json, sheetId) && json[sheetId] && json[sheetId].name) {
                        const sheet = json[sheetId];
                        tables[sheet.name] = {
                            headers: sheet.content[0] || [],
                            rows: sheet.content.slice(1)
                        };
                    }
                }
                return tables;
            }

            function renderUI(tables) {
                if (!tables) return;

                // --- 1. 渲染全局数据 ---
                const globalTable = tables["全局数据表"];
                const globalData = globalTable?.rows[0] || [];
                const globalHeaders = globalTable?.headers || [];

                document.getElementById('map-title').textContent = globalData[globalHeaders.indexOf("地图标题")] || '未知区域';
                document.getElementById('current-time').textContent = `当前时间：${globalData[globalHeaders.indexOf("当前时间")] || '----'}`;

                // --- 2. 渲染主角状态栏 ---
                const pInfoTable = tables["主角信息"];
                const pInfoHeaders = pInfoTable?.headers || [];
                const pInfo = pInfoTable?.rows[0] || [];

                // 加载主角头像（优先从本地存储加载）
                loadProtagonistAvatar('', '主角');

                if (pInfo.length > 0) {
                    // 基本信息
                    document.getElementById('protagonist-name').textContent = pInfo[pInfoHeaders.indexOf("人物名称")] || '主角';
                    const detailsContainer = document.getElementById('protagonist-details');
                    detailsContainer.innerHTML = `
                        <div class="detail-item">${pInfo[pInfoHeaders.indexOf("性别/年龄")] || '未知'}</div>
                        <div class="detail-item">${pInfo[pInfoHeaders.indexOf("职业/身份")] || '未知'}</div>
                    `;
                    // 移除金钱和雷达图的显示
                    document.getElementById('protagonist-money').textContent = '';
                    const statsContainer = document.querySelector('.protagonist-stats-container');
                    if(statsContainer) statsContainer.style.display = 'none';
                }

                // --- 3. 渲染重要人物按钮 (包括主角) ---
                const characterBar = document.getElementById('character-bar');
                characterBar.innerHTML = '';

                // 首先添加主角按钮
                if (pInfo.length > 0) {
                     const pBtn = document.createElement('button');
                     pBtn.className = 'function-btn';
                     pBtn.innerHTML = `<i class="fas fa-user-circle"></i> ${pInfo[pInfoHeaders.indexOf("人物名称")] || '主角'}`;
                     pBtn.onclick = () => openCharacterModal({
                         isProtagonist: true,
                         info: pInfo, infoHeaders: pInfoHeaders
                     });
                     characterBar.appendChild(pBtn);
                }

                const characters = tables["重要人物表"]?.rows || [];
                const charHeaders = tables["重要人物表"]?.headers || [];
                const protagonistName = pInfo[pInfoHeaders.indexOf("人物名称")];
                characters.forEach(charData => {
                    const charName = charData[charHeaders.indexOf('姓名')];
                    // 过滤掉主角本人，因为已在上面独立添加
                    if (charName && charName !== protagonistName) {
                        const isDeparted = charData[charHeaders.indexOf('是否离场')] === '是';
                        const charBtn = document.createElement('button');
                        charBtn.className = 'function-btn';
                        charBtn.innerHTML = `<i class="fas fa-id-badge"></i> ${charName}`;
                        charBtn.onclick = () => openCharacterModal({ info: charData, infoHeaders: charHeaders });
                        if (isDeparted) {
                            charBtn.style.display = 'none';
                        }
                        characterBar.appendChild(charBtn);
                    }
                });

                // --- 4. 设置弹窗内容 ---
                setupModalContent('skill-modal', 'skill-items-container', tables["主角技能表"], (item, headers) => {
                    const listItem = document.createElement('li');
                    listItem.className = 'list-item';

                    const content = document.createElement('div');
                    content.className = 'list-item-content';
                    const skillName = item[headers.indexOf('技能名称')];
                    content.innerHTML = `
                        <div class="item-name">${skillName} <small>[${item[headers.indexOf('等级/阶段')]}]</small></div>
                        <div class="item-details">${item[headers.indexOf('效果描述')]}</div>
                    `;

                    const useButton = document.createElement('button');
                    useButton.className = 'use-button';
                    useButton.textContent = '使用';
                    useButton.onclick = () => sendGameActionRequest(`使用技能 ${skillName}`);

                    listItem.appendChild(content);
                    listItem.appendChild(useButton);
                    return listItem;
                });
                setupModalContent('inventory-modal', 'inventory-items-container', tables["背包物品表"], (item, headers) => {
                    const listItem = document.createElement('li');
                    listItem.className = 'list-item';

                    const content = document.createElement('div');
                    content.className = 'list-item-content';
                    const itemName = item[headers.indexOf('物品名称')];
                    content.innerHTML = `
                        <div class="item-name">${itemName} (x${item[headers.indexOf('数量')]})</div>
                        <div class="item-details">${item[headers.indexOf('描述/效果')]}</div>
                    `;

                    const useButton = document.createElement('button');
                    useButton.className = 'use-button';
                    useButton.textContent = '使用';
                    useButton.onclick = () => sendGameActionRequest(`使用物品 ${itemName}`);

                    listItem.appendChild(content);
                    listItem.appendChild(useButton);
                    return listItem;
                });
                setupModalContent('quest-modal', 'quest-items-container', tables["任务与事件表"], (item, headers) => {
                    const listItem = document.createElement('li');
                    listItem.className = 'list-item';
                    listItem.innerHTML = `
                        <div class="quest-item">
                            <div class="item-name">${item[headers.indexOf('任务名称')]} <small>[${item[headers.indexOf('任务类型')]}]</small></div>
                            <div class="item-details"><b>发布者:</b> ${item[headers.indexOf('发布者')]}</div>
                            <div class="item-details"><b>描述:</b> ${item[headers.indexOf('详细描述')]}</div>
                            <div class="item-details"><b>进度:</b> ${item[headers.indexOf('当前进度')]}</div>
                        </div>
                    `;
                    return listItem;
                });

                // Render Map and External Areas
                const locations = [];
                const mainLocTable = tables["主要地点表"];
                const elementsTable = tables["地图元素表"];
                const elementsByLocation = {};

                if (elementsTable?.rows) {
                    elementsTable.rows.forEach(elRow => {
                        const locName = elRow[elementsTable.headers.indexOf('所属主地点')];
                        if (!locName) return;
                        if (!elementsByLocation[locName]) elementsByLocation[locName] = [];
                        elementsByLocation[locName].push({
                            name: elRow[elementsTable.headers.indexOf('元素名称')],
                            type: elRow[elementsTable.headers.indexOf('元素类型')],
                            description: elRow[elementsTable.headers.indexOf('元素描述')],
                            status: elRow[elementsTable.headers.indexOf('状态')],
                            interactions: [
                                elRow[elementsTable.headers.indexOf('互动选项1')],
                                elRow[elementsTable.headers.indexOf('互动选项2')],
                                elRow[elementsTable.headers.indexOf('互动选项3')]
                            ].filter(Boolean)
                        });
                    });
                }

                if (mainLocTable?.rows) {
                    mainLocTable.rows.forEach(locRow => {
                        const name = locRow[mainLocTable.headers.indexOf('地点名称')];
                        const x = parseInt(locRow[mainLocTable.headers.indexOf('X坐标')]);
                        const y = parseInt(locRow[mainLocTable.headers.indexOf('Y坐标')]);
                        const width = parseInt(locRow[mainLocTable.headers.indexOf('宽度')]);
                        const height = parseInt(locRow[mainLocTable.headers.indexOf('高度')]);
                        if (name && !isNaN(x) && !isNaN(y) && !isNaN(width) && !isNaN(height)) {
                            locations.push({
                                name, x, y, width, height,
                                description: locRow[mainLocTable.headers.indexOf('环境描述')],
                                elements: elementsByLocation[name] || []
                            });
                        }
                    });
                }

                // 从主角信息表获取主角当前位置
                const protagonistLocation = pInfo[pInfoHeaders.indexOf("主角当前所在地点")];
                renderMap(locations, protagonistLocation);

                const externalAreas = (globalData[globalHeaders.indexOf("外部区域列表")] || '').split(/[,，；;]/).map(s => s.trim()).filter(Boolean);
                renderExternalAreas(externalAreas);
            }

            /**
             * 当图片加载失败时，应用一个备用UI（彩色背景加问号）。
             * @param {HTMLElement} element - 图片的容器元素。
             */
            function applyImageFallback(element) {
                if (!element) return;
                const colors = ['#5a5a5a', '#6a4c4c', '#4c6a4c', '#4c4c6a', '#6a6a4c', '#4c6a6a'];
                const randomColor = colors[Math.floor(Math.random() * colors.length)];

                element.innerHTML = ''; // 清除损坏的img标签
                element.style.backgroundImage = 'none';
                element.style.backgroundColor = randomColor;
                element.style.display = 'flex';
                element.style.justifyContent = 'center';
                element.style.alignItems = 'center';
                element.style.color = '#fff';
                const size = Math.min(element.offsetWidth, element.offsetHeight);
                element.style.fontSize = `${size * 0.6}px`;
                element.style.fontWeight = 'bold';
                element.style.lineHeight = '1';
                element.textContent = '?';
            }

            /**
             * 从多个来源加载主角头像，并提供强大的回退机制。
             * @param {string} avatarUrlFromData - 从数据源获取的头像URL。
             * @param {string} protagonistName - 主角名字，用于localStorage的键。
             */
            function loadProtagonistAvatar(avatarUrlFromData, protagonistName) {
                const container = document.getElementById('protagonist-portrait-container');
                const imgElement = document.getElementById('protagonist-portrait-img');
                const customAvatarKey = 'protagonist-custom-avatar-主角';
                const customAvatar = localStorage.getItem(customAvatarKey);
                const defaultAvatar = "data:image/svg+xml,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 100 100'%3E%3Ctext y='.9em' font-size='90'%3E👤%3C/text%3E%3C/svg%3E";

                // 清理旧的UI元素（如图标和重置按钮）
                const existingResetBtn = container.querySelector('.avatar-reset-btn');
                if (existingResetBtn) existingResetBtn.remove();

                // 确保图片和容器恢复正常样式
                imgElement.style.display = 'block';
                container.style.backgroundColor = '#e0d5c8';
                // 如果容器里有文字（比如fallback的问号），先清空
                if(container.textContent) container.textContent = '';
                // 确保图片元素在容器里
                if(!container.contains(imgElement)) container.appendChild(imgElement);



                const sources = [];
                if (customAvatar) sources.push(customAvatar);
                if (avatarUrlFromData && (avatarUrlFromData.startsWith('http') || avatarUrlFromData.startsWith('data:'))) {
                    sources.push(avatarUrlFromData);
                }
                sources.push(defaultAvatar);

                let sourceIndex = 0;
                const tryNextSource = () => {
                    if (sourceIndex >= sources.length) {
                        applyImageFallback(container);
                        return;
                    }
                    imgElement.src = sources[sourceIndex];
                    sourceIndex++;
                };

                imgElement.onerror = tryNextSource;
                tryNextSource();
            }

            document.getElementById('protagonist-portrait-container').addEventListener('click', () => {
                const customAvatarKey = 'protagonist-custom-avatar-主角';

                const input = document.createElement('input');
                input.type = 'file';
                input.accept = "image/*";
                input.onchange = (event) => {
                    const file = event.target.files[0];
                    if (!file) return;

                    const reader = new FileReader();
                    reader.onload = (e) => {
                        const img = new Image();
                        img.onload = () => {
                            const canvas = document.createElement('canvas');
                            const ctx = canvas.getContext('2d');
                            const TARGET_SIZE = 300;
                            canvas.width = TARGET_SIZE;
                            canvas.height = TARGET_SIZE;

                            // 裁剪为正方形
                            const size = Math.min(img.width, img.height);
                            const x = (img.width - size) / 2;
                            const y = (img.height - size) / 2;

                            ctx.drawImage(img, x, y, size, size, 0, 0, TARGET_SIZE, TARGET_SIZE);

                            const dataUrl = canvas.toDataURL('image/png');

                            try {
                                localStorage.setItem(customAvatarKey, dataUrl);
                                const imgElement = document.getElementById('protagonist-portrait-img');
                                imgElement.src = dataUrl;
                            } catch (err) {
                                console.error("保存自定义头像失败:", err);
                                alert('图片太大或浏览器缓存已满，无法保存。请尝试清理浏览器缓存或使用更小的图片。');
                            }
                        };
                        img.src = e.target.result;
                    };
                    reader.readAsDataURL(file);
                };
                input.click();
            });

            function drawRadarChart(stats, canvasId) {
                const canvas = document.getElementById(canvasId);
                if (!canvas || !canvas.getContext) return;

                const ctx = canvas.getContext('2d');
                const width = canvas.width;
                const height = canvas.height;
                const centerX = width / 2;
                const centerY = height / 2;
                const radius = width / 2 - 20; // 留出标签空间

                const labels = ["力量", "敏捷", "体质", "智力", "感知", "魅力"];
                // 确保即使数据不全，也按固定顺序和数量渲染
                const values = labels.map(label => stats[label] || 0);
                const numStats = labels.length;
                if (numStats === 0) return;

                ctx.clearRect(0, 0, width, height);

                // Draw radar shape
                ctx.beginPath();
                for (let i = 0; i < numStats; i++) {
                    const angle = (Math.PI * 2 / numStats) * i - Math.PI / 2;
                    const value = Math.max(0, Math.min(30, values[i])) / 30; // Normalize to 0-1, max value 30 for scale
                    const x = centerX + radius * value * Math.cos(angle);
                    const y = centerY + radius * value * Math.sin(angle);
                    if (i === 0) {
                        ctx.moveTo(x, y);
                    } else {
                        ctx.lineTo(x, y);
                    }
                }
                ctx.closePath();
                ctx.fillStyle = 'rgba(180, 138, 92, 0.5)';
                ctx.fill();
                ctx.strokeStyle = 'rgba(62, 39, 26, 0.8)';
                ctx.stroke();

                // Draw labels
                const labelContainer = canvas.parentElement;
                // Clear previous labels
                labelContainer.querySelectorAll('.stat-label').forEach(el => el.remove());

                labels.forEach((label, i) => {
                    const angle = (Math.PI * 2 / numStats) * i - Math.PI / 2;
                    const labelRadius = radius + 10;
                    const x = centerX + labelRadius * Math.cos(angle);
                    const y = centerY + labelRadius * Math.sin(angle);

                    const labelEl = document.createElement('div');
                    labelEl.className = 'stat-label';
                    labelEl.textContent = label.charAt(0);
                    labelEl.style.left = `${x}px`;
                    labelEl.style.top = `${y}px`;
                    labelContainer.appendChild(labelEl);
                });
            }

            function openModal(modalId) { document.getElementById(modalId).classList.add('visible'); }
            function closeModal(modalId) { document.getElementById(modalId).classList.remove('visible'); }

            /**
             * 检查两个矩形是否重叠（带边距）。
             * @param {object} rect1 - {x, y, width, height}
             * @param {object} rect2 - {x, y, width, height}
             * @returns {boolean} - 如果重叠则返回 true。
             */
            function checkOverlap(rect1, rect2) {
                var margin = 10; // 增加边距防止标签接触
                return (rect1.x < rect2.x + rect2.width + margin &&
                        rect1.x + rect1.width + margin > rect2.x &&
                        rect1.y < rect2.y + rect2.height + margin &&
                        rect1.y + rect1.height + margin > rect2.y);
            }

            /**
             * 使用简单的力导向算法调整布局，以最小化重叠。
             * @param {Array<object>} locations - 地点对象数组。
             * @returns {Array<object>} - 修改后的地点对象数组。
             */
            function adjustLayoutForOverlaps(locations) {
                if (!locations || locations.length < 2) return locations;
                var iterations = 150, forceFactor = 0.5;
                for (var i = 0; i < iterations; i++) {
                    for (var j = 0; j < locations.length; j++) {
                        for (var k = j + 1; k < locations.length; k++) {
                            var locA = locations[j], locB = locations[k];
                            if (checkOverlap(locA, locB)) {
                                var dx = (locA.x + locA.width / 2) - (locB.x + locB.width / 2);
                                var dy = (locA.y + locA.height / 2) - (locB.y + locB.height / 2);
                                var distance = Math.sqrt(dx * dx + dy * dy);
                                if (distance === 0) { // 防止除零
                                    dx = (Math.random() - 0.5) * 0.1;
                                    dy = (Math.random() - 0.5) * 0.1;
                                    distance = Math.sqrt(dx * dx + dy * dy);
                                }
                                var overlapX = (locA.width / 2 + locB.width / 2) - Math.abs(dx);
                                var overlapY = (locA.height / 2 + locB.height / 2) - Math.abs(dy);
                                if (overlapX > 0 && overlapY > 0) {
                                    var moveX = (dx / distance) * overlapX * forceFactor;
                                    var moveY = (dy / distance) * overlapY * forceFactor;
                                    locA.x += moveX; locA.y += moveY;
                                    locB.x -= moveX; locB.y -= moveY;
                                }
                            }
                        }
                    }
                }
                return locations;
            }

            function renderMap(locations, protagonistLocation) {
                // 在渲染前调整布局以避免重叠
                if (locations && locations.length > 0) {
                    locations = adjustLayoutForOverlaps(locations);
                }
                const svg = document.getElementById('visual-map');
                svg.innerHTML = '';
                if (!locations || locations.length === 0) {
                    svg.setAttribute('viewBox', '0 0 800 600');
                    const text = document.createElementNS("http://www.w3.org/2000/svg", 'text');
                    text.setAttribute('x', '400');
                    text.setAttribute('y', '300');
                    text.setAttribute('class', 'map-location-label');
                    text.textContent = '暂无地图数据';
                    svg.appendChild(text);
                    return;
                }

                let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
                locations.forEach(l => {
                    minX = Math.min(minX, l.x);
                    minY = Math.min(minY, l.y);
                    maxX = Math.max(maxX, l.x + l.width);
                    maxY = Math.max(maxY, l.y + l.height);
                });

                const padding = Math.max((maxX - minX) * 0.1, (maxY - minY) * 0.1, 50);
                const vbX = minX - padding, vbY = minY - padding;
                const vbW = (maxX - minX) + (padding * 2);
                const vbH = (maxY - minY) + (padding * 2);
                svg.setAttribute('viewBox', `${vbX} ${vbY} ${vbW} ${vbH}`);

                locations.forEach(loc => {
                    const g = document.createElementNS("http://www.w3.org/2000/svg", 'g');
                    g.setAttribute('class', 'map-location-group');
                    g.addEventListener('click', () => openLocationModal(loc));

                    const r = document.createElementNS("http://www.w3.org/2000/svg", 'rect');
                    r.setAttribute('x', loc.x);
                    r.setAttribute('y', loc.y);
                    r.setAttribute('width', loc.width);
                    r.setAttribute('height', loc.height);
                    r.setAttribute('class', 'map-location-rect');
                    r.setAttribute('rx', '8'); // Rounded corners to match theme

                    const t = document.createElementNS("http://www.w3.org/2000/svg", 'text');
                    t.setAttribute('x', loc.x + loc.width / 2);
                    t.setAttribute('y', loc.y + loc.height / 2);
                    t.setAttribute('class', 'map-location-label');
                    t.textContent = loc.name;

                    g.appendChild(r);
                    g.appendChild(t);
                    svg.appendChild(g);

                    // 如果是主角所在位置，添加头像标记
                    if (loc.name === protagonistLocation) {
                        const protagonistImgSrc = document.getElementById('protagonist-portrait-img').src;
                        const avatarGroup = document.createElementNS("http://www.w3.org/2000/svg", 'g');
                        avatarGroup.setAttribute('class', 'protagonist-map-avatar');

                        // 创建外围的脉冲波circle
                        const pulseCircle = document.createElementNS("http://www.w3.org/2000/svg", 'circle');
                        pulseCircle.setAttribute('cx', loc.x + loc.width / 2);
                        pulseCircle.setAttribute('cy', loc.y + loc.height / 2);
                        pulseCircle.setAttribute('r', '12'); // 初始半径
                        pulseCircle.setAttribute('class', 'pulse-wave');

                        // 创建用作头像的image元素
                        const avatarImage = document.createElementNS("http://www.w3.org/2000/svg", 'image');
                        avatarImage.setAttribute('x', loc.x + loc.width / 2 - 12);
                        avatarImage.setAttribute('y', loc.y + loc.height / 2 - 12);
                        avatarImage.setAttribute('width', '24');
                        avatarImage.setAttribute('height', '24');
                        avatarImage.setAttribute('href', protagonistImgSrc);

                        // 创建一个圆形剪裁蒙版
                        const clipPath = document.createElementNS('http://www.w3.org/2000/svg', 'clipPath');
                        const clipPathId = 'avatar-clip-path';
                        clipPath.setAttribute('id', clipPathId);
                        const clipCircle = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
                        clipCircle.setAttribute('cx', loc.x + loc.width / 2);
                        clipCircle.setAttribute('cy', loc.y + loc.height / 2);
                        clipCircle.setAttribute('r', '12');
                        clipPath.appendChild(clipCircle);

                        avatarImage.setAttribute('clip-path', `url(#${clipPathId})`);

                        avatarGroup.appendChild(clipPath);
                        avatarGroup.appendChild(pulseCircle);
                        avatarGroup.appendChild(avatarImage);
                        svg.appendChild(avatarGroup);
                    }
                });
            }

            function renderExternalAreas(areas) {
                const container = document.getElementById('external-areas-list');
                container.innerHTML = '';
                if (!areas || areas.length === 0) {
                    container.innerHTML = `<p style="opacity: 0.7;">无其他可探索区域</p>`;
                    return;
                }
                areas.forEach(area => {
                    const btn = document.createElement('button');
                    btn.className = 'function-btn';
                    btn.innerHTML = `<i class="fas fa-map-signs"></i> ${area}`;
                    btn.onclick = () => sendGameActionRequest(`前往 ${area}`);
                    container.appendChild(btn);
                });
            }

            function openLocationModal(loc) {
                const modal = document.getElementById('map-element-modal');
                modal.querySelector('#modal-element-name').textContent = loc.name;

                const contentContainer = modal.querySelector('#modal-element-description');
                contentContainer.innerHTML = `<p>${loc.description || '暂无描述'}</p>`;

                const interactionsContainer = modal.querySelector('#modal-element-interactions');
                interactionsContainer.innerHTML = '';
                // Use flex to center the single button
                interactionsContainer.style.display = 'flex';
                interactionsContainer.style.justifyContent = 'center';

                if (loc.elements && loc.elements.length > 0) {
                    contentContainer.innerHTML += `<h5 style="margin-top: 20px; margin-bottom: 10px; font-family: var(--font-title); color: var(--text-title);">可互动元素:</h5>`;
                    loc.elements.forEach(el => {
                        const elBtn = document.createElement('button');
                        elBtn.className = 'function-btn';
                        elBtn.style.width = '100%';
                        elBtn.style.marginBottom = '5px';
                        elBtn.style.textAlign = 'left';
                        elBtn.textContent = `${el.name} (${el.status})`;
                        elBtn.onclick = (e) => {
                            e.stopPropagation(); // Prevent modal from closing
                            openMapElementModal(el);
                        };
                        contentContainer.appendChild(elBtn);
                    });
                }

                const goHereBtn = document.createElement('button');
                goHereBtn.className = 'function-btn';
                goHereBtn.style.width = 'auto'; // Override full-width grid style
                goHereBtn.innerHTML = `<i class="fas fa-shoe-prints"></i> 到这里去`;
                goHereBtn.onclick = () => {
                    sendGameActionRequest(`前往 ${loc.name}`);
                    closeModal('map-element-modal');
                };
                interactionsContainer.appendChild(goHereBtn);

                openModal('map-element-modal');
            }

            function openMapElementModal(el) {
                 const modal = document.getElementById('map-element-modal');
                 modal.querySelector('#modal-element-name').textContent = el.name;
                 modal.querySelector('#modal-element-description').innerHTML = `<p>${el.description}</p><p><b>状态:</b> ${el.status}</p>`;

                 const interactionsContainer = modal.querySelector('#modal-element-interactions');
                 interactionsContainer.innerHTML = '';
                 // Reset container style to default grid for multiple buttons
                 interactionsContainer.style.display = '';
                 interactionsContainer.style.justifyContent = '';
                 el.interactions.forEach(action => {
                     const btn = document.createElement('button');
                     btn.className = 'function-btn';
                     btn.textContent = action;
                     btn.onclick = () => {
                         sendGameActionRequest(action);
                         closeModal('map-element-modal');
                     };
                     interactionsContainer.appendChild(btn);
                 });
                 openModal('map-element-modal');
            }

            function openCharacterModal(character) {
                const modal = document.getElementById('character-modal');
                const nameEl = document.getElementById('modal-character-name');
                const contentContainer = document.getElementById('modal-character-content');
                const interactionsContainer = document.getElementById('modal-character-interactions');

                contentContainer.innerHTML = '';
                interactionsContainer.innerHTML = '';
                nameEl.textContent = character.info[character.infoHeaders.indexOf(character.isProtagonist ? "人物名称" : "姓名")] || '未知';

                const descFragment = document.createDocumentFragment();
                let details;

                if (character.isProtagonist) {
                    details = [
                        { label: '性别/年龄', value: character.info[character.infoHeaders.indexOf('性别/年龄')] }, 
                        { label: '外貌', value: character.info[character.infoHeaders.indexOf('外貌特征')] }, 
                        { label: '职业/身份', value: character.info[character.infoHeaders.indexOf('职业/身份')] },
                        { label: '性格', value: character.info[character.infoHeaders.indexOf('性格特点')] },
                        { label: '过往经历', value: character.info[character.infoHeaders.indexOf('过往经历')] }
                    ];
                } else {
                    details = [
                        { label: '性别/年龄', value: character.info[character.infoHeaders.indexOf('性别/年龄')] }, 
                        { label: '外貌', value: character.info[character.infoHeaders.indexOf('外貌特征')] }, 
                        { label: '性格', value: character.info[character.infoHeaders.indexOf('性格特点')] },
                        { label: '持有物品', value: character.info[character.infoHeaders.indexOf('持有的重要物品')] },
                        { label: '好感度', value: character.info[character.infoHeaders.indexOf('好感度')] },
                        { label: '过往经历', value: character.info[character.infoHeaders.indexOf('过往经历')] }
                    ];
                }

                details.forEach(detail => {
                    if (detail.value !== null && detail.value !== undefined) {
                        const p = document.createElement('p');
                        const value = typeof detail.value === 'string' ? detail.value.replace(/\n/g, '<br>') : detail.value;
                        p.innerHTML = `<strong>${detail.label}:</strong> ${value}`;
                        descFragment.appendChild(p);
                    }
                });
                contentContainer.appendChild(descFragment);

                const interactFragment = document.createDocumentFragment();
                if (character.isProtagonist) {
                    const interactionHeaders = ["选项一", "选项二", "选项三", "选项四"];
                    interactionHeaders.forEach(header => {
                        const interactionText = character.info[character.infoHeaders.indexOf(header)];
                        if (interactionText) {
                            const button = document.createElement('button');
                            button.className = 'function-btn interaction-button';
                            button.textContent = interactionText;
                            button.onclick = () => {
                                sendGameActionRequest(interactionText);
                                closeModal('character-modal');
                            };
                            interactFragment.appendChild(button);
                        }
                    });
                }

                if (interactFragment.hasChildNodes()) {
                    interactionsContainer.appendChild(interactFragment);
                    interactionsContainer.style.display = 'grid';
                } else {
                    interactionsContainer.innerHTML = ''; // For non-protagonists, clear it
                    interactionsContainer.style.display = 'none';
                }

                openModal('character-modal');
            }

            function setupModalContent(modalId, containerId, tableData, createItemElement) {
