            // Bind button events
            document.getElementById('skill-button').onclick = () => openModal('skill-modal');
            document.getElementById('inventory-button').onclick = () => openModal('inventory-modal');
            document.getElementById('quest-button').onclick = () => openModal('quest-modal');
            // document.getElementById('shop-button').onclick = () => openModal('shop-modal');

            // Re-bind close for protagonist/character modal specifically, as it might be recreated
            const charModal = document.getElementById('character-modal');
            if(charModal){
                charModal.querySelector('.close-modal-button').onclick = () => closeModal('character-modal');
            }


            // Map pan and zoom logic
            const svg = document.getElementById('visual-map');
            let viewBox = { x: 0, y: 0, w: 800, h: 600 };
            let isPanning = false;
            let startPoint = { x: 0, y: 0 };

            function updateViewBox() {
                const vb = svg.getAttribute('viewBox').split(' ').map(Number);
                viewBox = { x: vb[0], y: vb[1], w: vb[2], h: vb[3] };
                svg.setAttribute('viewBox', `${viewBox.x} ${viewBox.y} ${viewBox.w} ${viewBox.h}`);
            }

            document.getElementById('zoom-in-btn').addEventListener('click', () => {
                const vb = svg.getAttribute('viewBox').split(' ').map(Number);
                viewBox = { x: vb[0], y: vb[1], w: vb[2], h: vb[3] };
                const newW = viewBox.w * 0.9;
                const newH = viewBox.h * 0.9;
                viewBox.x += (viewBox.w - newW) / 2;
                viewBox.y += (viewBox.h - newH) / 2;
                viewBox.w = newW;
                viewBox.h = newH;
                svg.setAttribute('viewBox', `${viewBox.x} ${viewBox.y} ${viewBox.w} ${viewBox.h}`);
            });

            document.getElementById('zoom-out-btn').addEventListener('click', () => {
                const vb = svg.getAttribute('viewBox').split(' ').map(Number);
                viewBox = { x: vb[0], y: vb[1], w: vb[2], h: vb[3] };
                const newW = viewBox.w * 1.1;
                const newH = viewBox.h * 1.1;
                viewBox.x += (viewBox.w - newW) / 2;
                viewBox.y += (viewBox.h - newH) / 2;
                viewBox.w = newW;
                viewBox.h = newH;
                svg.setAttribute('viewBox', `${viewBox.x} ${viewBox.y} ${viewBox.w} ${viewBox.h}`);
            });

            svg.addEventListener('mousedown', (e) => {
                if (e.buttons !== 1) return; // Only pan on left click
                isPanning = true;
                startPoint = { x: e.clientX, y: e.clientY };
                svg.style.cursor = 'grabbing';
            });
             svg.addEventListener('mousemove', (e) => {
                if (!isPanning) return;
                const vb = svg.getAttribute('viewBox').split(' ').map(Number);
                viewBox = { x: vb[0], y: vb[1], w: vb[2], h: vb[3] };
                const endPoint = { x: e.clientX, y: e.clientY };
                const dx = (startPoint.x - endPoint.x) * (viewBox.w / svg.clientWidth);
                const dy = (startPoint.y - endPoint.y) * (viewBox.h / svg.clientHeight);
                viewBox.x += dx;
                viewBox.y += dy;
                svg.setAttribute('viewBox', `${viewBox.x} ${viewBox.y} ${viewBox.w} ${viewBox.h}`);
                startPoint = endPoint;
            });
            const stopPanning = () => {
                isPanning = false;
                svg.style.cursor = 'grab';
            };
            svg.addEventListener('mouseup', stopPanning);
            svg.addEventListener('mouseleave', stopPanning);

            // Bind close buttons for all modals
            document.querySelectorAll('.modal-overlay').forEach(modal => {
                modal.querySelector('.close-modal-button').onclick = () => modal.classList.remove('visible');
                // Also close on overlay click
                modal.addEventListener('click', function(event) {
                    if (event.target === this) {
                        this.classList.remove('visible');
                    }
                });
            });
        });
    </script>
